// Types and helpers shared between the MCP Panorama API and its UI.

import type { McpStatus } from "~~/shared/data/mcp-landscape"

export type Layer = "industry" | "public"

export interface ToolDto {
  id: number
  slug: string
  name: string
  nameZh: string | null
  status: McpStatus
  depsCount: number
  blurb: string
  blurbZh: string
  tags: string[]
  /** When status === "released", the marketplace listing slug. */
  extensionSlug: string | null
  ownerPrimary: string
  ownerSecondary: string | null
}

export interface StatusCounts {
  released: number
  dev: number
  none: number
}

export interface GroupStats {
  total: number
  counts: StatusCounts
  releasedPct: number
  activePct: number
  lagPct: number
}

export interface PdtBlock {
  key: string
  label: string
  labelZh: string
  items: ToolDto[]
}

export interface SectorGroup {
  kind: "sector"
  key: string
  label: string
  labelZh: string
  short: string
  items: ToolDto[]
  stats: GroupStats
}

export interface DomainGroup {
  kind: "domain"
  key: string
  label: string
  labelZh: string
  short: string
  items: ToolDto[]
  pdts: PdtBlock[]
  stats: GroupStats
}

export type Group = SectorGroup | DomainGroup

export interface LayerPayload {
  layer: Layer
  layerStats: GroupStats
  groups: Group[]
}

export type RankKey = "leading" | "onTrack" | "lagging" | "early"

/** Returns the rank label for a group's stats — null if too small or middling. */
export function rankFor(stats: GroupStats): RankKey | null {
  if (stats.total < 3) return null
  if (stats.releasedPct >= 75) return "leading"
  if (stats.releasedPct >= 50) return "onTrack"
  if (stats.lagPct >= 50) return "lagging"
  if (stats.releasedPct < 25) return "early"
  return null
}

export const STATUS_ORDER: McpStatus[] = ["none", "dev", "released"]

/** Localised display name for a tool (Chinese fallback to English when null). */
export function toolDisplayName(tool: ToolDto, locale: string): string {
  if (locale === "zh" && tool.nameZh) return tool.nameZh
  return tool.name
}

/** Localised display blurb. */
export function toolDisplayBlurb(tool: ToolDto, locale: string): string {
  return locale === "zh" ? tool.blurbZh : tool.blurb
}

/** Localised group title. */
export function groupDisplayTitle(g: Group, locale: string): string {
  return locale === "zh" ? g.labelZh : g.label
}

export function pdtDisplayTitle(p: PdtBlock, locale: string): string {
  return locale === "zh" ? p.labelZh : p.label
}

import { sql } from "drizzle-orm";
import {
  boolean,
  check,
  index,
  integer,
  pgEnum,
  pgTable,
  serial,
  text,
  timestamp,
} from "drizzle-orm/pg-core";

import { extensions } from "./extension";

export const mcpLayerEnum = pgEnum("mcp_layer", ["industry", "public"]);

// Industry sectors. PK is the design-time slug ("wireless", "cloud", …).
export const mcpSectors = pgTable("mcp_sectors", {
  key: text().primaryKey(),
  label: text().notNull(),
  labelZh: text().notNull(),
  short: text().notNull(),
  sortOrder: integer().notNull(),
});

// Public service domains (AI R&D, Hardware, …).
export const mcpDomains = pgTable("mcp_domains", {
  key: text().primaryKey(),
  label: text().notNull(),
  labelZh: text().notNull(),
  short: text().notNull(),
  sortOrder: integer().notNull(),
});

// PDTs (Product Development Teams) within a domain.
export const mcpPdts = pgTable(
  "mcp_pdts",
  {
    key: text().primaryKey(),
    domainKey: text()
      .notNull()
      .references(() => mcpDomains.key, { onDelete: "cascade" }),
    label: text().notNull(),
    labelZh: text().notNull(),
    sortOrder: integer().notNull(),
  },
  (t) => [index("idx_mcp_pdts_domain_sort").on(t.domainKey, t.sortOrder)],
);

// One row per traditional internal tool service. Status is *derived* —
// extensionId set ⇒ released; else inDev ⇒ dev; else none.
export const mcpLandscapeTools = pgTable(
  "mcp_landscape_tools",
  {
    id: serial().primaryKey(),
    slug: text().notNull().unique(),
    name: text().notNull(),
    nameZh: text(),
    layer: mcpLayerEnum().notNull(),
    ownerSector: text().references(() => mcpSectors.key, {
      onDelete: "restrict",
    }),
    ownerDomain: text().references(() => mcpDomains.key, {
      onDelete: "restrict",
    }),
    // TODO: a composite FK on (ownerDomain, ownerPdt) → (mcpPdts.domainKey, mcpPdts.key)
    // would let the DB enforce that the PDT actually belongs to the domain. Today
    // the seed is the only writer and keeps them aligned; revisit when an admin UI
    // can mutate landscape rows.
    ownerPdt: text().references(() => mcpPdts.key, { onDelete: "restrict" }),
    // Marketplace MCP listing. Non-null ⇒ tool is "released".
    extensionId: text().references(() => extensions.id, {
      onDelete: "set null",
    }),
    inDev: boolean().notNull().default(false),
    depsCount: integer().notNull().default(0),
    blurb: text().notNull(),
    blurbZh: text().notNull(),
    tags: text().array().notNull().default(sql`ARRAY[]::text[]`),
    updatedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [
    index("idx_mcp_tools_layer_sector").on(t.layer, t.ownerSector),
    index("idx_mcp_tools_layer_domain_pdt").on(
      t.layer,
      t.ownerDomain,
      t.ownerPdt,
    ),
    index("idx_mcp_tools_extension").on(t.extensionId),
    // A tool can be released or in-dev or neither — not both.
    check(
      "mcp_tools_status_xor",
      sql`NOT ("extension_id" IS NOT NULL AND "in_dev" = true)`,
    ),
    // Industry tools own a sector; public tools own a domain (and usually a PDT).
    check(
      "mcp_tools_owner_layer",
      sql`(layer = 'industry' AND owner_sector IS NOT NULL AND owner_domain IS NULL AND owner_pdt IS NULL)
        OR (layer = 'public' AND owner_sector IS NULL AND owner_domain IS NOT NULL)`,
    ),
  ],
);

import { asc, eq, isNotNull } from "drizzle-orm"

import { useDb } from "~~/server/utils/db"
import { deriveStatus, type McpStatus } from "~~/shared/data/mcp-landscape"
import {
  extensions,
  mcpDomains,
  mcpLandscapeTools,
  mcpPdts,
  mcpSectors,
} from "~~/shared/db/schema"
import type {
  DomainGroup,
  Group,
  GroupStats,
  Layer,
  LayerPayload,
  PdtBlock,
  SectorGroup,
  StatusCounts,
  ToolDto,
} from "~~/shared/mcp-panorama"

export type {
  DomainGroup,
  Group,
  GroupStats,
  Layer,
  LayerPayload,
  PdtBlock,
  SectorGroup,
  StatusCounts,
  ToolDto,
}

function blankCounts(): StatusCounts {
  return { released: 0, dev: 0, none: 0 }
}

function computeStats(items: { status: McpStatus }[]): GroupStats {
  const counts = blankCounts()
  for (const item of items) counts[item.status]++
  const total = items.length
  if (total === 0) {
    return { total, counts, releasedPct: 0, activePct: 0, lagPct: 0 }
  }
  return {
    total,
    counts,
    releasedPct: Math.round((counts.released / total) * 100),
    activePct: Math.round(((counts.released + counts.dev) / total) * 100),
    lagPct: Math.round((counts.none / total) * 100),
  }
}

export async function getLandscape(layer: Layer): Promise<LayerPayload> {
  const db = useDb()
  // One join across the four tables; pgsql returns ordered rows.
  const rows = await db
    .select({
      id: mcpLandscapeTools.id,
      slug: mcpLandscapeTools.slug,
      name: mcpLandscapeTools.name,
      nameZh: mcpLandscapeTools.nameZh,
      blurb: mcpLandscapeTools.blurb,
      blurbZh: mcpLandscapeTools.blurbZh,
      tags: mcpLandscapeTools.tags,
      depsCount: mcpLandscapeTools.depsCount,
      extensionId: mcpLandscapeTools.extensionId,
      inDev: mcpLandscapeTools.inDev,
      ownerSector: mcpLandscapeTools.ownerSector,
      ownerDomain: mcpLandscapeTools.ownerDomain,
      ownerPdt: mcpLandscapeTools.ownerPdt,
      extensionSlug: extensions.slug,
    })
    .from(mcpLandscapeTools)
    .leftJoin(extensions, eq(mcpLandscapeTools.extensionId, extensions.id))
    .where(eq(mcpLandscapeTools.layer, layer))
    .orderBy(asc(mcpLandscapeTools.id))

  const tools: ToolDto[] = rows.map((r) => {
    const status = deriveStatus({
      extensionId: r.extensionId,
      inDev: r.inDev,
    })
    const ownerPrimary = layer === "industry" ? r.ownerSector! : r.ownerDomain!
    return {
      id: r.id,
      slug: r.slug,
      name: r.name,
      nameZh: r.nameZh,
      status,
      depsCount: r.depsCount,
      blurb: r.blurb,
      blurbZh: r.blurbZh,
      tags: r.tags,
      extensionSlug: status === "released" ? r.extensionSlug : null,
      ownerPrimary,
      ownerSecondary: r.ownerPdt,
    }
  })

  const layerStats = computeStats(tools)

  let groups: Group[]
  if (layer === "industry") {
    const sectors = await db
      .select()
      .from(mcpSectors)
      .orderBy(asc(mcpSectors.sortOrder))

    groups = sectors
      .map((s): SectorGroup => {
        const items = tools.filter((t) => t.ownerPrimary === s.key)
        return {
          kind: "sector" as const,
          key: s.key,
          label: s.label,
          labelZh: s.labelZh,
          short: s.short,
          items,
          stats: computeStats(items),
        }
      })
      .filter((g) => g.items.length > 0)
  } else {
    const [domains, pdts] = await Promise.all([
      db.select().from(mcpDomains).orderBy(asc(mcpDomains.sortOrder)),
      db
        .select()
        .from(mcpPdts)
        .where(isNotNull(mcpPdts.domainKey))
        .orderBy(asc(mcpPdts.sortOrder)),
    ])

    groups = domains
      .map((d): DomainGroup => {
        const items = tools.filter((t) => t.ownerPrimary === d.key)
        const domainPdts = pdts
          .filter((p) => p.domainKey === d.key)
          .map((p): PdtBlock => ({
            key: p.key,
            label: p.label,
            labelZh: p.labelZh,
            items: items.filter((t) => t.ownerSecondary === p.key),
          }))
          .filter((p) => p.items.length > 0)
        return {
          kind: "domain" as const,
          key: d.key,
          label: d.label,
          labelZh: d.labelZh,
          short: d.short,
          items,
          pdts: domainPdts,
          stats: computeStats(items),
        }
      })
      .filter((g) => g.items.length > 0)
  }

  return { layer, layerStats, groups }
}

import { sql } from "drizzle-orm";
import {
  bigint,
  boolean,
  customType,
  index,
  integer,
  jsonb,
  numeric,
  pgEnum,
  pgTable,
  primaryKey,
  text,
  timestamp,
  unique,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { departments, organizations } from "./org";

// tsvector is a Postgres-native type; Drizzle doesn't ship a built-in helper.
// We declare it as a custom type so the ORM can reference it in WHERE clauses
// via sql``. It is GENERATED ALWAYS (read-only); never written by app code.
const tsvector = customType<{ data: string }>({
  dataType() { return "tsvector"; },
});

export const extensionCategoryEnum = pgEnum("extension_category", [
  "skills",
  "mcp",
  "slash",
  "plugins",
]);

export const extensionScopeEnum = pgEnum("extension_scope", [
  "personal",
  "org",
  "enterprise",
]);

export const extensionBadgeEnum = pgEnum("extension_badge", [
  "official",
  "popular",
  "new",
]);

export const funcCatEnum = pgEnum("func_cat", [
  "workTask",
  "business",
  "tools",
]);

export const visibilityEnum = pgEnum("extension_visibility", [
  "draft",
  "published",
  "archived",
]);

export const versionStatusEnum = pgEnum("version_status", [
  "pending",
  "scanning",
  "ready",
  "rejected",
]);

export const fileScanStatusEnum = pgEnum("file_scan_status", [
  "pending",
  "clean",
  "flagged",
]);

export const extensions = pgTable(
  "extensions",
  {
    id: text().primaryKey(),
    slug: text().notNull().unique(),
    category: extensionCategoryEnum().notNull(),
    badge: extensionBadgeEnum(),
    scope: extensionScopeEnum().notNull(),
    // funcCat/subCat are nullable — the redesigned publish wizard does not
    // collect them; admin curation can backfill or system defaults apply.
    funcCat: funcCatEnum(),
    subCat: text(),
    l2: text(),
    publisherUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    ownerOrgId: text()
      .notNull()
      .references(() => organizations.id, { onDelete: "cascade" }),
    deptId: text().references(() => departments.id, { onDelete: "set null" }),
    iconEmoji: text(),
    iconColor: text(),
    visibility: visibilityEnum().notNull().default("draft"),
    // Editorial flag — hand-curated. Surfaces a single extension on the home
    // hero. Coexists with `badge`: badge is a static editorial mark on the
    // card; `featured` is a transient "pick of the week" pointer.
    featured: boolean().notNull().default(false),
    // i18n columns
    name: text().notNull(),
    nameZh: text(),
    tagline: text(),
    taglineZh: text(),
    description: text(),
    descriptionZh: text(),
    // Long-form markdown body for the detail page. Not duplicated to ZH yet —
    // most extensions will have an English README, with translations layered
    // on later if needed.
    readmeMd: text(),
    // metadata for detail page sidebar
    homepageUrl: text(),
    repoUrl: text(),
    licenseSpdx: text(),
    compatibilityJson: jsonb(),
    // Permissions captured during publish (network/files/runtime/data, etc.).
    // Surfaced on the detail page so users see what the extension wants.
    permissions: jsonb().notNull().default({}),
    // denormalized counters (updated by jobs)
    downloadsCount: integer().notNull().default(0),
    starsAvg: numeric({ precision: 2, scale: 1 }).notNull().default("0.0"),
    ratingsCount: integer().notNull().default(0),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    searchVector: tsvector("search_vector"),
  },
  (t) => [
    index("idx_ext_category").on(t.category),
    index("idx_ext_scope").on(t.scope),
    index("idx_ext_func_sub_l2").on(t.funcCat, t.subCat, t.l2),
    index("idx_ext_dept_path").using(
      "btree",
      sql`${t.deptId} text_pattern_ops`,
    ),
    index("idx_ext_visibility").on(t.visibility),
    index("idx_ext_downloads").on(sql`${t.downloadsCount} DESC`),
    index("idx_ext_stars").on(sql`${t.starsAvg} DESC`),
    index("idx_ext_featured_published").on(
      t.featured,
      sql`${t.publishedAt} DESC`,
    ),
  ],
);

export const extensionVersions = pgTable(
  "extension_versions",
  {
    id: text().primaryKey(),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    version: text().notNull(), // semver
    changelog: text(),
    changelogZh: text(),
    manifestJson: jsonb(),
    // Logical reference to files.id; no FK constraint to avoid a circular FK
    // with files.extensionVersionId. App code keeps these consistent.
    bundleFileId: text(),
    status: versionStatusEnum().notNull().default("pending"),
    // Source method chosen during publish: zip (only one wired today), git, cli.
    // Stored as text rather than enum so adding methods doesn't require a migration.
    sourceMethod: text().notNull().default("zip"),
    sourceMeta: jsonb().notNull().default({}),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [unique("ext_version_unique").on(t.extensionId, t.version)],
);

export const files = pgTable("files", {
  id: text().primaryKey(),
  extensionVersionId: text().references(() => extensionVersions.id, {
    onDelete: "set null",
  }),
  r2Key: text().notNull(),
  size: bigint({ mode: "bigint" }).notNull(),
  checksumSha256: text().notNull(),
  mimeType: text(),
  scanStatus: fileScanStatusEnum().notNull().default("pending"),
  scanReport: jsonb(),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const tags = pgTable("tags", {
  id: text().primaryKey(), // tag key, e.g. "real-time"
  labelEn: text().notNull(),
  labelZh: text().notNull(),
});

export const extensionTags = pgTable(
  "extension_tags",
  {
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    tagId: text()
      .notNull()
      .references(() => tags.id, { onDelete: "cascade" }),
  },
  (t) => [
    primaryKey({ columns: [t.extensionId, t.tagId] }),
    index("idx_extension_tags_tag_ext").on(t.tagId, t.extensionId),
  ],
);

// Idempotent MCP-landscape seed.
//
// Safe to run on every deploy. Unlike scripts/seed.ts (which TRUNCATEs to
// produce a clean demo state), this script only upserts the static MCP
// landscape — taxonomy + tool rows + marketplace extension stubs the
// panorama links to. Re-running has no destructive effect on user data,
// other extensions, departments, tags, etc.
//
// Wired into the Vercel build via `vercel-build` so the panorama page
// always has data on a freshly deployed environment.
//
// Also imported by scripts/seed.ts so the demo seed and the standalone
// seed share one source of truth.

import { sql } from "drizzle-orm"
import { drizzle, type PostgresJsDatabase } from "drizzle-orm/postgres-js"
import postgres from "postgres"

import {
  INDUSTRY_SECTORS,
  MCP_TOOLS,
  PUBLIC_DOMAINS,
  ownerToParts,
} from "../shared/data/mcp-landscape"
import * as schema from "../shared/db/schema"
import {
  extensions,
  mcpDomains,
  mcpLandscapeTools,
  mcpPdts,
  mcpSectors,
  organizations,
} from "../shared/db/schema"

type Db = PostgresJsDatabase<typeof schema>

const SYSTEM_ORG_ID = "default"

/**
 * Upserts the static MCP landscape: a single owner org for the marketplace
 * stubs, the sector/domain/PDT taxonomy, the released-tool extension stubs,
 * and the landscape tool rows. Re-runnable; never destructive.
 */
export async function seedMcpLandscape(db: Db): Promise<void> {
  // Owner org for the marketplace extension stubs. We upsert by id so the
  // demo seed's `default` org (when present) is preserved verbatim, and a
  // fresh deploy can stand the row up on its own.
  await db
    .insert(organizations)
    .values({
      id: SYSTEM_ORG_ID,
      slug: SYSTEM_ORG_ID,
      name: "Default Organization",
      nameZh: "默认组织",
    })
    .onConflictDoNothing({ target: organizations.id })

  // Sectors.
  const sectorRows = INDUSTRY_SECTORS.map((s, i) => ({
    key: s.key,
    label: s.label,
    labelZh: s.labelZh,
    short: s.short,
    sortOrder: i,
  }))
  console.log(`seed-mcp: upserting ${sectorRows.length} sectors`)
  await db
    .insert(mcpSectors)
    .values(sectorRows)
    .onConflictDoUpdate({
      target: mcpSectors.key,
      set: {
        label: sql`excluded.label`,
        labelZh: sql`excluded.label_zh`,
        short: sql`excluded.short`,
        sortOrder: sql`excluded.sort_order`,
      },
    })

  // Domains.
  const domainRows = PUBLIC_DOMAINS.map((d, i) => ({
    key: d.key,
    label: d.label,
    labelZh: d.labelZh,
    short: d.short,
    sortOrder: i,
  }))
  console.log(`seed-mcp: upserting ${domainRows.length} domains`)
  await db
    .insert(mcpDomains)
    .values(domainRows)
    .onConflictDoUpdate({
      target: mcpDomains.key,
      set: {
        label: sql`excluded.label`,
        labelZh: sql`excluded.label_zh`,
        short: sql`excluded.short`,
        sortOrder: sql`excluded.sort_order`,
      },
    })

  // PDTs.
  const pdtRows = PUBLIC_DOMAINS.flatMap((d) =>
    d.pdts.map((p, i) => ({
      key: `${d.key}.${p.key}`,
      domainKey: d.key,
      label: p.label,
      labelZh: p.labelZh,
      sortOrder: i,
    })),
  )
  console.log(`seed-mcp: upserting ${pdtRows.length} PDTs`)
  await db
    .insert(mcpPdts)
    .values(pdtRows)
    .onConflictDoUpdate({
      target: mcpPdts.key,
      set: {
        domainKey: sql`excluded.domain_key`,
        label: sql`excluded.label`,
        labelZh: sql`excluded.label_zh`,
        sortOrder: sql`excluded.sort_order`,
      },
    })

  // Marketplace MCP extension stubs — one per released tool. `publisherUserId`
  // is left null on auto-seed so we don't require the demo creator rows; the
  // demo seed can override these afterwards if it runs.
  const releasedTools = MCP_TOOLS.filter((t) => t.released)
  const mcpExtRows = releasedTools.map((t) => ({
    id: `mcp-${t.slug}`,
    slug: t.slug,
    category: "mcp" as const,
    badge: null,
    scope: "enterprise" as const,
    funcCat: null,
    subCat: null,
    publisherUserId: null,
    ownerOrgId: SYSTEM_ORG_ID,
    deptId: null,
    iconEmoji: null,
    iconColor: null,
    visibility: "published" as const,
    name: t.name,
    nameZh: t.nameZh ?? null,
    tagline: t.blurb,
    taglineZh: t.blurbZh,
    description: t.blurb,
    descriptionZh: t.blurbZh,
    readmeMd: `# ${t.name}\n\nMCP server for **${t.name}** — ${t.blurb}.\n\n## Install\n\n\`\`\`bash\nagentcenter install ${t.slug}\n\`\`\`\n`,
    publishedAt: new Date(),
  }))
  console.log(`seed-mcp: upserting ${mcpExtRows.length} marketplace stubs`)
  await db
    .insert(extensions)
    .values(mcpExtRows)
    .onConflictDoUpdate({
      target: extensions.id,
      set: {
        slug: sql`excluded.slug`,
        category: sql`excluded.category`,
        scope: sql`excluded.scope`,
        ownerOrgId: sql`excluded.owner_org_id`,
        visibility: sql`excluded.visibility`,
        name: sql`excluded.name`,
        nameZh: sql`excluded.name_zh`,
        tagline: sql`excluded.tagline`,
        taglineZh: sql`excluded.tagline_zh`,
        description: sql`excluded.description`,
        descriptionZh: sql`excluded.description_zh`,
        readmeMd: sql`excluded.readme_md`,
        updatedAt: sql`now()`,
      },
    })

  // Landscape tool rows. extensionId is set for "released" tools, inDev for
  // those in development, otherwise the tool has no MCP and renders grey.
  const toolRows = MCP_TOOLS.map((t) => {
    const parts = ownerToParts(t.owner)
    return {
      slug: t.slug,
      name: t.name,
      nameZh: t.nameZh ?? null,
      layer: parts.layer,
      ownerSector: parts.layer === "industry" ? parts.primary : null,
      ownerDomain: parts.layer === "public" ? parts.primary : null,
      ownerPdt:
        parts.layer === "public" && parts.secondary
          ? `${parts.primary}.${parts.secondary}`
          : null,
      extensionId: t.released ? `mcp-${t.slug}` : null,
      inDev: t.inDev,
      depsCount: t.depsCount,
      blurb: t.blurb,
      blurbZh: t.blurbZh,
      tags: t.tags,
    }
  })
  console.log(`seed-mcp: upserting ${toolRows.length} landscape tools`)
  await db
    .insert(mcpLandscapeTools)
    .values(toolRows)
    .onConflictDoUpdate({
      target: mcpLandscapeTools.slug,
      set: {
        name: sql`excluded.name`,
        nameZh: sql`excluded.name_zh`,
        layer: sql`excluded.layer`,
        ownerSector: sql`excluded.owner_sector`,
        ownerDomain: sql`excluded.owner_domain`,
        ownerPdt: sql`excluded.owner_pdt`,
        extensionId: sql`excluded.extension_id`,
        inDev: sql`excluded.in_dev`,
        depsCount: sql`excluded.deps_count`,
        blurb: sql`excluded.blurb`,
        blurbZh: sql`excluded.blurb_zh`,
        tags: sql`excluded.tags`,
        updatedAt: sql`now()`,
      },
    })
}

// ─── Standalone entry-point: `bun scripts/seed-mcp-landscape.ts` ──────────────
async function main() {
  const url = process.env.DATABASE_URL
  if (!url) {
    console.error("seed-mcp: DATABASE_URL is not set")
    process.exit(1)
  }
  const client = postgres(url)
  const db = drizzle(client, { schema, casing: "snake_case" })

  console.log("seed-mcp: starting")
  await seedMcpLandscape(db)
  console.log("seed-mcp: done")
  await client.end()
}

// Bun-friendly check for "is this the entry script?" — true when invoked
// directly via `bun scripts/seed-mcp-landscape.ts`, false when imported.
// `Bun.main` and `import.meta.url` both work; pick the standard one.
const isEntry = import.meta.url === `file://${process.argv[1]}`
if (isEntry) {
  main()
    .then(() => process.exit(0))
    .catch((err) => {
      console.error("seed-mcp: failed")
      console.error(err)
      process.exit(1)
    })
}

