// ─── Tools + MCPs ────────────────────────────────────────────────────────────
// Compact constructors keep the source close to the original design data.

function toSlug(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
}

function tool(
  name: string,
  owner: string,
  blurb: string,
  blurbZh: string,
  mcps: McpSeed[],
  opts: { nameZh?: string } = {},
): McpToolSeed {
  return {
    slug: toSlug(name),
    name,
    nameZh: opts.nameZh,
    owner,
    blurb,
    blurbZh,
    mcps,
  }
}

function mcp(
  slug: string,
  status: McpStatus,
  depsCount: number,
  blurb: string,
  blurbZh: string,
  tags: string[],
  opts: { name?: string; nameZh?: string } = {},
): McpSeed {
  return {
    slug,
    name: opts.name,
    nameZh: opts.nameZh,
    released: status === "released",
    inDev: status === "dev",
    depsCount,
    blurb,
    blurbZh,
    tags,
  }
}

/** Convenience: a tool with a single MCP whose slug is `<tool-slug>-mcp` and
 * which inherits the tool's blurb/name. Most tools use this shape; multi-MCP
 * tools (like CodeCheck) call `tool(...)` with an explicit mcps[] instead. */
function singleMcpTool(
  name: string,
  owner: string,
  status: McpStatus,
  depsCount: number,
  blurb: string,
  blurbZh: string,
  tags: string[],
  opts: { nameZh?: string } = {},
): McpToolSeed {
  const slug = toSlug(name)
  return tool(name, owner, blurb, blurbZh, [
    mcp(`${slug}-mcp`, status, depsCount, blurb, blurbZh, tags),
  ], opts)
}

/** Convenience: a tool with **no** MCPs yet — renders a single placeholder
 * tile. Used for "none"-status tools so they still appear in the panorama. */
function noMcpTool(
  name: string,
  owner: string,
  blurb: string,
  blurbZh: string,
  opts: { nameZh?: string } = {},
): McpToolSeed {
  return tool(name, owner, blurb, blurbZh, [], opts)
}

